package com.vaultsurvival.plugin.currency;

import com.vaultsurvival.plugin.VaultSurvivalPlugin;
import org.bukkit.Bukkit;
import org.bukkit.entity.Player;
import java.sql.PreparedStatement;
import java.util.UUID;
import java.util.concurrent.CompletableFuture;

/** Idempotent issuance/payout path. Cash is first made durable in a recovery locker, then delivered. */
public final class PayoutDeliveryService{
    public record Delivery(UUID transactionUuid,UUID cashUuid,long amount,boolean replayed){}
    private final VaultSurvivalPlugin plugin;private final CashRecoveryService recovery;
    public PayoutDeliveryService(VaultSurvivalPlugin plugin,CashRecoveryService recovery){this.plugin=plugin;this.recovery=recovery;}
    public CompletableFuture<Delivery> deliver(Player recipient,long amount,UUID issuedBy,String source,String idempotencyKey){return deliver(recipient,amount,issuedBy,source,idempotencyKey,(connection,plan)->{});}
    public CompletableFuture<Delivery> deliver(Player recipient,long amount,UUID issuedBy,String source,String idempotencyKey,CashBusinessMutation business){if(!Bukkit.isPrimaryThread())return CompletableFuture.failedFuture(new IllegalStateException("Payout delivery must capture the player on the main thread"));if(amount<=0)return CompletableFuture.failedFuture(new IllegalArgumentException("Payout amount must be positive"));UUID player=recipient.getUniqueId();return plugin.getDatabase().write(c->{try(PreparedStatement existing=c.prepareStatement("SELECT j.transaction_uuid,d.cash_uuid,d.amount FROM cash_transaction_journal j JOIN cash_recovery_deliveries d ON d.transaction_uuid=j.transaction_uuid WHERE j.idempotency_key=?")){existing.setString(1,idempotencyKey);try(var r=existing.executeQuery()){if(r.next())return new Delivery(UUID.fromString(r.getString(1)),UUID.fromString(r.getString(2)),r.getLong(3),true);}}UUID transaction=UUID.randomUUID(),cash=UUID.randomUUID();long now=System.currentTimeMillis();try(PreparedStatement item=c.prepareStatement("INSERT INTO cash_items(cash_uuid,amount,state,created_at,last_seen_at,location_type,location_id,owner_uuid,created_by,issued_by,original_owner,current_holder) VALUES(?,?,'ACTIVE',datetime('now'),datetime('now'),'RECOVERY_LOCKER',?,?,?,?,?,?)")){item.setString(1,cash.toString());item.setLong(2,amount);item.setString(3,player.toString());item.setString(4,player.toString());item.setString(5,issuedBy==null?null:issuedBy.toString());item.setString(6,issuedBy==null?null:issuedBy.toString());item.setString(7,player.toString());item.setString(8,player.toString());item.executeUpdate();}try(PreparedStatement journal=c.prepareStatement("INSERT INTO cash_transaction_journal(transaction_uuid,idempotency_key,player_uuid,state,requested_amount,change_amount,destination_type,destination_id,plan_data,created_at,updated_at,recovery_attempts) VALUES(?,?,?,'RECOVERY_REQUIRED',?,0,'PAYOUT',?,?,?, ?,0)")){journal.setString(1,transaction.toString());journal.setString(2,idempotencyKey);journal.setString(3,player.toString());journal.setLong(4,amount);journal.setString(5,source);journal.setString(6,"issued:"+cash);journal.setLong(7,now);journal.setLong(8,now);journal.executeUpdate();}try(PreparedStatement delivery=c.prepareStatement("INSERT INTO cash_recovery_deliveries(transaction_uuid,cash_uuid,player_uuid,amount,state,created_at,updated_at) VALUES(?,?,?,?,'PENDING',?,?)")){delivery.setString(1,transaction.toString());delivery.setString(2,cash.toString());delivery.setString(3,player.toString());delivery.setLong(4,amount);delivery.setLong(5,now);delivery.setLong(6,now);delivery.executeUpdate();}CashPaymentPlan synthetic=new CashPaymentPlan(transaction,idempotencyKey,player,java.util.List.of(),amount,0,"PAYOUT",source,java.util.List.of("PAYOUT"));business.apply(c,synthetic);return new Delivery(transaction,cash,amount,false);}).thenApply(delivery->{Bukkit.getScheduler().runTask(plugin,()->recovery.deliverPending(recipient));return delivery;});}
}
